-- ─── Fix LinkedIn Posts: Replace inflated metrics with correct Buffer data ────
-- Run this in the Supabase SQL editor to correct LinkedIn post metrics.
-- This deletes all existing LinkedIn posts and re-inserts with accurate Buffer data.
-- ─────────────────────────────────────────────────────────────────────────────

BEGIN;

-- Step 1: Remove all existing LinkedIn posts
DELETE FROM posts WHERE platform = 'linkedin';

-- Step 2: Insert correct LinkedIn posts from Buffer export
ON CONFLICT (platform, post_id) DO UPDATE SET
  content = EXCLUDED.content,
  published_at = EXCLUDED.published_at,
  likes = EXCLUDED.likes,
  impressions = EXCLUDED.impressions,
  comments = EXCLUDED.comments,
  post_type = EXCLUDED.post_type,
  source = EXCLUDED.source;

COMMIT;
